#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std;const int max_users=1000005;bool seen[max_users];int  main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<vector<ll>>a(n,vector<ll>());        for(int i=0;i<n;i++){            int m;            cin>>m;            vector<ll>v(m);            for(int j=0;j<m;j++){                cin>>v[j];            }            a[i]=v;        }        vector<bool>used_blog(n,false);        vector<ll>ans;                for(int step=0;step<n;step++){            int blog=-1;            vector<ll>best;            for(int i=0;i<n;i++){                if(used_blog[i])continue;                vector<ll>temp;                for(int j=a[i].size()-1;j>=0;j--){                    ll user=a[i][j];                    if(!seen[user]){                        temp.push_back(user);                        seen[user]=true;                    }                }                for(ll user:temp){                    seen[user]=false;                }                 if(blog == -1 || temp<best){                    best=temp;                    blog=i;                }            }            used_blog[blog]=true;            for(ll user:best){                ans.push_back(user);                seen[user]=true;            }        }        for(ll user:ans){            cout<<user<<" ";        }        cout<<"\n";        for(ll user:ans){            seen[user]=false;        }    } }